package scriptmanager.service;

import java.util.List;
import java.util.Map;

public interface CoordinationService {
    List<Map<String, Object>> getFullSchedule();

    List<Map<String, Object>> getResourceUsageByTime();

    List<Map<String, Object>> getMasterTimeline();

    List<Map<String, Object>> getWorkflowAlerts();

    List<Map<String, Object>> getPreEventChecklist();

    List<Map<String, Object>> getLiveOperationBoard();

    List<Map<String, Object>> getPostEventReconciliation();
}

package scriptmanager.service;

import java.util.List;
import java.util.Map;

public interface CoordinationService {
    List<Map<String, Object>> getFullSchedule();

    List<Map<String, Object>> getResourceUsageByTime();
}

package scriptmanager.service;

import scriptmanager.config.UserSession;
import scriptmanager.enums.UserRole;
import scriptmanager.config.HibernateUtil;
import org.hibernate.Session;
import org.hibernate.query.Query;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

public class CoordinationServiceImpl implements CoordinationService {

    @Override
    public List<Map<String, Object>> getFullSchedule() {
        List<Map<String, Object>> boardData = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, " +
                      "(SELECT COUNT(pcns) FROM hm.phanCongNhanSus pcns), " +
                      "(SELECT COUNT(pctb) FROM hm.phanCongThietBis pctb) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY hm.tgBatDau ASC"
                    : "SELECT hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, " +
                      "(SELECT COUNT(pcns) FROM hm.phanCongNhanSus pcns), " +
                      "(SELECT COUNT(pctb) FROM hm.phanCongThietBis pctb) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "ORDER BY hm.tgBatDau ASC";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }
            List<Object[]> results = query.list();

            for (Object[] row : results) {
                Map<String, Object> item = new HashMap<>();
                item.put("tenHangMuc", row[0]);
                item.put("tenSuKien", row[1]);
                item.put("batDau", row[2]);
                item.put("ketThuc", row[3]);
                item.put("soNhanSu", row[4]);
                item.put("soThietBi", row[5]);
                boardData.add(item);
            }
        }
        return boardData;
    }

    @Override
    public List<Map<String, Object>> getResourceUsageByTime() {
        List<Map<String, Object>> usageData = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT ns.tenNS, hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM PhanCongNhanSu pc " +
                      "JOIN pc.nhanSu ns " +
                      "JOIN pc.hangMuc hm " +
                      "JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY ns.tenNS, hm.tgBatDau"
                    : "SELECT ns.tenNS, hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM PhanCongNhanSu pc " +
                      "JOIN pc.nhanSu ns " +
                      "JOIN pc.hangMuc hm " +
                      "JOIN hm.suKienTiec sk " +
                      "ORDER BY ns.tenNS, hm.tgBatDau";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }
            List<Object[]> results = query.list();

            for (Object[] row : results) {
                Map<String, Object> usage = new HashMap<>();
                usage.put("tenNhanSu", row[0]);
                usage.put("tenHangMuc", row[1]);
                usage.put("tenSuKien", row[2]);
                usage.put("thoiGian", row[3] + " - " + row[4]);
                usageData.add(usage);
            }
        }
        return usageData;
    }

    @Override
    public List<Map<String, Object>> getMasterTimeline() {
        List<Map<String, Object>> items = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT sk.maSK, sk.tenSuKien, hm.maHM, hm.tenHM, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY sk.maSK, hm.tgBatDau, hm.maHM"
                    : "SELECT sk.maSK, sk.tenSuKien, hm.maHM, hm.tenHM, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "ORDER BY sk.maSK, hm.tgBatDau, hm.maHM";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }
            List<Object[]> rows = query.list();

            Map<Integer, Integer> seqMap = new HashMap<>();
            Map<Integer, String> prevMap = new HashMap<>();
            for (Object[] row : rows) {
                Integer maSK = (Integer) row[0];
                String tenSuKien = (String) row[1];
                Integer maHM = (Integer) row[2];
                String tenHM = (String) row[3];

                int seq = seqMap.getOrDefault(maSK, 0) + 1;
                seqMap.put(maSK, seq);

                Map<String, Object> item = new LinkedHashMap<>();
                item.put("maSuKien", maSK);
                item.put("tenSuKien", tenSuKien);
                item.put("thuTu", seq);
                item.put("maHangMuc", maHM);
                item.put("tenHangMuc", tenHM);
                item.put("batDau", row[4]);
                item.put("ketThuc", row[5]);
                item.put("phuThuoc", prevMap.getOrDefault(maSK, "-") );
                items.add(item);

                prevMap.put(maSK, tenHM);
            }
        }

        return items;
    }

    @Override
    public List<Map<String, Object>> getWorkflowAlerts() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        alerts.addAll(getNhanSuConflicts());
        alerts.addAll(getThietBiConflicts());
        alerts.addAll(getDaoCuShortages());
        alerts.addAll(getMissingOwnerAlerts());
        alerts.addAll(getPartnerConfirmationAlerts());
        return alerts;
    }

    @Override
    public List<Map<String, Object>> getPreEventChecklist() {
        List<Map<String, Object>> checklist = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT hm.maHM, hm.tenHM, sk.tenSuKien, " +
                      "(SELECT COUNT(pc) FROM hm.phanCongNhanSus pc), " +
                      "(SELECT COUNT(pctb) FROM hm.phanCongThietBis pctb), " +
                      "(SELECT COUNT(sddc) FROM hm.suDungDaoCus sddc), " +
                      "(SELECT COUNT(sdh) FROM hm.suDungHieuUngs sdh), " +
                      "(SELECT COUNT(nhac) FROM hm.danhSachNhacs nhac) " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY sk.tenSuKien, hm.tgBatDau"
                    : "SELECT hm.maHM, hm.tenHM, sk.tenSuKien, " +
                      "(SELECT COUNT(pc) FROM hm.phanCongNhanSus pc), " +
                      "(SELECT COUNT(pctb) FROM hm.phanCongThietBis pctb), " +
                      "(SELECT COUNT(sddc) FROM hm.suDungDaoCus sddc), " +
                      "(SELECT COUNT(sdh) FROM hm.suDungHieuUngs sdh), " +
                      "(SELECT COUNT(nhac) FROM hm.danhSachNhacs nhac) " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "ORDER BY sk.tenSuKien, hm.tgBatDau";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }

            for (Object[] row : query.list()) {
                long soNhanSu = (Long) row[3];
                long soThietBi = (Long) row[4];
                long soDaoCu = (Long) row[5];
                long soHieuUng = (Long) row[6];
                long soNhac = (Long) row[7];

                Map<String, Object> item = new LinkedHashMap<>();
                item.put("tenSuKien", row[2]);
                item.put("tenHangMuc", row[1]);
                item.put("nhanSu", soNhanSu > 0 ? "ĐẠT" : "THIẾU");
                item.put("thietBi", soThietBi > 0 ? "ĐẠT" : "THIẾU");
                item.put("daoCu", soDaoCu > 0 ? "ĐẠT" : "THIẾU");
                item.put("cue", (soHieuUng > 0 || soNhac > 0) ? "ĐẠT" : "THIẾU");
                item.put("sanSang", (soNhanSu > 0 && soThietBi > 0) ? "SẴN SÀNG" : "CHƯA SẴN SÀNG");
                checklist.add(item);
            }
        }

        return checklist;
    }

    @Override
    public List<Map<String, Object>> getLiveOperationBoard() {
        List<Map<String, Object>> board = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT sk.tenSuKien, hm.tenHM, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY hm.tgBatDau"
                    : "SELECT sk.tenSuKien, hm.tenHM, hm.tgBatDau, hm.tgKetThuc " +
                      "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                      "ORDER BY hm.tgBatDau";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }

            LocalDateTime now = LocalDateTime.now();
            for (Object[] row : query.list()) {
                LocalDateTime start = (LocalDateTime) row[2];
                LocalDateTime end = (LocalDateTime) row[3];
                String status = inferRuntimeStatus(now, start, end);

                Map<String, Object> item = new LinkedHashMap<>();
                item.put("tenSuKien", row[0]);
                item.put("tenHangMuc", row[1]);
                item.put("batDau", start);
                item.put("ketThuc", end);
                item.put("trangThai", status);
                board.add(item);
            }
        }

        return board;
    }

    @Override
    public List<Map<String, Object>> getPostEventReconciliation() {
        List<Map<String, Object>> report = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT sk.tenSuKien, " +
                      "COALESCE(SUM(pctb.soLuongSuDung), 0), " +
                      "COALESCE(SUM(sddc.soLuongSuDung), 0), " +
                      "COUNT(DISTINCT hm.maHM) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "LEFT JOIN hm.phanCongThietBis pctb " +
                      "LEFT JOIN hm.suDungDaoCus sddc " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "GROUP BY sk.tenSuKien " +
                      "ORDER BY sk.tenSuKien"
                    : "SELECT sk.tenSuKien, " +
                      "COALESCE(SUM(pctb.soLuongSuDung), 0), " +
                      "COALESCE(SUM(sddc.soLuongSuDung), 0), " +
                      "COUNT(DISTINCT hm.maHM) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "LEFT JOIN hm.phanCongThietBis pctb " +
                      "LEFT JOIN hm.suDungDaoCus sddc " +
                      "GROUP BY sk.tenSuKien " +
                      "ORDER BY sk.tenSuKien";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }

            for (Object[] row : query.list()) {
                Map<String, Object> item = new LinkedHashMap<>();
                item.put("tenSuKien", row[0]);
                item.put("tongThietBiDuKien", row[1]);
                item.put("tongDaoCuDuKien", row[2]);
                item.put("soHangMuc", row[3]);
                item.put("doiSoat", "Cần nhập số liệu thực tế");
                report.add(item);
            }
        }

        return report;
    }

    private List<Map<String, Object>> getNhanSuConflicts() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT ns.tenNS, hm1.tenHM, hm2.tenHM, hm1.tgBatDau, hm1.tgKetThuc " +
                    "FROM PhanCongNhanSu pc1 " +
                    "JOIN pc1.nhanSu ns " +
                    "JOIN pc1.hangMuc hm1, PhanCongNhanSu pc2 " +
                    "JOIN pc2.hangMuc hm2 " +
                    "WHERE pc2.nhanSu.maNS = ns.maNS " +
                    "AND hm1.maHM < hm2.maHM " +
                    "AND hm1.tgBatDau < hm2.tgKetThuc " +
                    "AND hm1.tgKetThuc > hm2.tgBatDau";
            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                Map<String, Object> item = new LinkedHashMap<>();
                item.put("mucDo", "CAO");
                item.put("loai", "Trùng lịch nhân sự");
                item.put("chiTiet", row[0] + ": " + row[1] + " <-> " + row[2]);
                alerts.add(item);
            }
        }
        return alerts;
    }

    private List<Map<String, Object>> getThietBiConflicts() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT tb.tenTB, tb.soLuong, COALESCE(SUM(pctb.soLuongSuDung),0) " +
                    "FROM PhanCongThietBi pctb JOIN pctb.thietBi tb GROUP BY tb.maTB, tb.tenTB, tb.soLuong";
            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                long tongDung = (Long) row[2];
                int tonKho = (Integer) row[1];
                if (tongDung > tonKho) {
                    Map<String, Object> item = new LinkedHashMap<>();
                    item.put("mucDo", "CAO");
                    item.put("loai", "Thiếu thiết bị");
                    item.put("chiTiet", row[0] + " cần " + tongDung + ", tồn kho " + tonKho);
                    alerts.add(item);
                }
            }
        }
        return alerts;
    }

    private List<Map<String, Object>> getDaoCuShortages() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT dc.tenDaoCu, dc.soLuong, COALESCE(SUM(sddc.soLuongSuDung),0) " +
                    "FROM SuDungDaoCu sddc JOIN sddc.daoCu dc GROUP BY dc.maDaoCu, dc.tenDaoCu, dc.soLuong";
            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                long tongDung = (Long) row[2];
                int tonKho = (Integer) row[1];
                if (tongDung > tonKho) {
                    Map<String, Object> item = new LinkedHashMap<>();
                    item.put("mucDo", "CAO");
                    item.put("loai", "Thiếu đạo cụ");
                    item.put("chiTiet", row[0] + " cần " + tongDung + ", tồn kho " + tonKho);
                    alerts.add(item);
                }
            }
        }
        return alerts;
    }

    private List<Map<String, Object>> getMissingOwnerAlerts() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT hm.tenHM, sk.tenSuKien " +
                    "FROM HangMucKichBan hm JOIN hm.suKienTiec sk " +
                    "WHERE (SELECT COUNT(pc) FROM hm.phanCongNhanSus pc) = 0";
            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                Map<String, Object> item = new LinkedHashMap<>();
                item.put("mucDo", "TRUNG BÌNH");
                item.put("loai", "Hạng mục thiếu người phụ trách");
                item.put("chiTiet", row[1] + " / " + row[0]);
                alerts.add(item);
            }
        }
        return alerts;
    }

    private List<Map<String, Object>> getPartnerConfirmationAlerts() {
        List<Map<String, Object>> alerts = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT DISTINCT sk.tenSuKien, dt.tenDonVi " +
                    "FROM PhanCongThietBi pctb " +
                    "JOIN pctb.hangMuc hm " +
                    "JOIN hm.suKienTiec sk " +
                    "JOIN pctb.thietBi tb " +
                    "JOIN tb.doiTac dt";

            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                Map<String, Object> item = new LinkedHashMap<>();
                item.put("mucDo", "TRUNG BÌNH");
                item.put("loai", "Đối tác chưa xác nhận");
                item.put("chiTiet", row[0] + " / " + row[1] + " (chưa có module xác nhận)");
                alerts.add(item);
            }
        }
        return alerts;
    }

    private String inferRuntimeStatus(LocalDateTime now, LocalDateTime start, LocalDateTime end) {
        if (start == null || end == null) {
            return "THIẾU THỜI GIAN";
        }
        if (now.isBefore(start)) {
            return "CHỜ";
        }
        if (!now.isAfter(end)) {
            return "ĐANG CHẠY";
        }
        return "ĐÃ XONG";
    }
}

package scriptmanager.service;

import org.hibernate.Session;
import org.hibernate.query.Query;
import scriptmanager.config.HibernateUtil;
import scriptmanager.config.UserSession;
import scriptmanager.enums.UserRole;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CoordinationServiceImpl implements CoordinationService {

    @Override
    public List<Map<String, Object>> getFullSchedule() {
        List<Map<String, Object>> boardData = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, " +
                      "(SELECT COUNT(pcns) FROM hm.phanCongNhanSus pcns) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY hm.tgBatDau ASC"
                    : "SELECT hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, " +
                      "(SELECT COUNT(pcns) FROM hm.phanCongNhanSus pcns) " +
                      "FROM HangMucKichBan hm " +
                      "JOIN hm.suKienTiec sk " +
                      "ORDER BY hm.tgBatDau ASC";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }

            for (Object[] row : query.list()) {
                Map<String, Object> item = new HashMap<>();
                item.put("tenHangMuc", row[0]);
                item.put("tenSuKien", row[1]);
                item.put("batDau", row[2]);
                item.put("ketThuc", row[3]);
                item.put("soNhanSu", row[4]);
                boardData.add(item);
            }
        }

        return boardData;
    }

    @Override
    public List<Map<String, Object>> getResourceUsageByTime() {
        List<Map<String, Object>> usageData = new ArrayList<>();

        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Integer currentUserId = UserSession.getCurrentUserId();
            boolean scopedToUser = UserSession.getCurrentRole() == UserRole.USER && currentUserId != null;

            String hql = scopedToUser
                    ? "SELECT ns.tenNS, hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, pc.nhiemVu " +
                      "FROM PhanCongNhanSu pc " +
                      "JOIN pc.nhanSu ns " +
                      "JOIN pc.hangMuc hm " +
                      "JOIN hm.suKienTiec sk " +
                      "WHERE sk.nguoiDung.maND = :maND " +
                      "ORDER BY sk.tenSuKien, hm.tgBatDau, ns.tenNS"
                    : "SELECT ns.tenNS, hm.tenHM, sk.tenSuKien, hm.tgBatDau, hm.tgKetThuc, pc.nhiemVu " +
                      "FROM PhanCongNhanSu pc " +
                      "JOIN pc.nhanSu ns " +
                      "JOIN pc.hangMuc hm " +
                      "JOIN hm.suKienTiec sk " +
                      "ORDER BY sk.tenSuKien, hm.tgBatDau, ns.tenNS";

            Query<Object[]> query = session.createQuery(hql, Object[].class);
            if (scopedToUser) {
                query.setParameter("maND", currentUserId);
            }

            for (Object[] row : query.list()) {
                Map<String, Object> usage = new HashMap<>();
                usage.put("tenNhanSu", row[0]);
                usage.put("tenHangMuc", row[1]);
                usage.put("tenSuKien", row[2]);
                usage.put("thoiGian", row[3] + " - " + row[4]);
                usage.put("nhiemVu", row[5] == null ? "" : row[5]);
                usageData.add(usage);
            }
        }

        return usageData;
    }
}

package scriptmanager.service;

import org.hibernate.Session;
import org.hibernate.Transaction;
import scriptmanager.config.HibernateUtil;
import scriptmanager.entity.assignment.PhanCongNhanSu;
import scriptmanager.entity.assignment.pk.PhanCongNhanSuId;
import scriptmanager.entity.core.HangMucKichBan;
import scriptmanager.entity.user.NhanSu;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

public class PhanCongNhanSuService {

    public List<Map<String, Object>> findAllView() {
        List<Map<String, Object>> rows = new ArrayList<>();
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            String hql = "SELECT sk.maSK, sk.tenSuKien, hm.maHM, hm.tenHM, ns.maNS, ns.tenNS, pc.nhiemVu " +
                    "FROM PhanCongNhanSu pc " +
                    "JOIN pc.hangMuc hm " +
                    "JOIN hm.suKienTiec sk " +
                    "JOIN pc.nhanSu ns " +
                    "ORDER BY sk.maSK, hm.tgBatDau, ns.tenNS";
            for (Object[] row : session.createQuery(hql, Object[].class).list()) {
                Map<String, Object> item = new LinkedHashMap<>();
                item.put("maSK", row[0]);
                item.put("tenSuKien", row[1]);
                item.put("maHM", row[2]);
                item.put("tenHangMuc", row[3]);
                item.put("maNS", row[4]);
                item.put("tenNhanSu", row[5]);
                item.put("nhiemVu", row[6]);
                rows.add(item);
            }
        }
        return rows;
    }

    public void assignNhanSuToEvent(int maSK, int maNS, String nhiemVu) {
        AuthorizationService.requireManagerOrAdmin();

        String normalizedTask = nhiemVu == null ? "" : nhiemVu.trim();
        if (maSK <= 0 || maNS <= 0) {
            throw new IllegalArgumentException("Mã sự kiện và mã nhân sự phải hợp lệ.");
        }

        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();

            NhanSu nhanSu = session.get(NhanSu.class, maNS);
            if (nhanSu == null) {
                throw new IllegalArgumentException("Không tìm thấy nhân sự.");
            }

            // Lấy toàn bộ hạng mục của sự kiện để phân công đồng loạt.
            List<HangMucKichBan> hangMucs = session.createQuery(
                            "FROM HangMucKichBan hm WHERE hm.suKienTiec.maSK = :maSK ORDER BY hm.tgBatDau ASC",
                            HangMucKichBan.class)
                    .setParameter("maSK", maSK)
                    .list();

            if (hangMucs.isEmpty()) {
                throw new IllegalArgumentException("Sự kiện chưa có hạng mục để phân công nhân sự.");
            }

            // Nếu đã có bản ghi thì cập nhật nhiệm vụ, chưa có thì tạo mới.
            for (HangMucKichBan hangMuc : hangMucs) {
                PhanCongNhanSuId id = new PhanCongNhanSuId(hangMuc.getMaHM(), maNS);
                PhanCongNhanSu existing = session.get(PhanCongNhanSu.class, id);
                if (existing == null) {
                    PhanCongNhanSu created = new PhanCongNhanSu();
                    created.setHangMuc(hangMuc);
                    created.setNhanSu(nhanSu);
                    created.setNhiemVu(normalizedTask);
                    session.persist(created);
                } else {
                    existing.setNhiemVu(normalizedTask);
                }
            }

            transaction.commit();
        } catch (Exception ex) {
            if (transaction != null) {
                transaction.rollback();
            }
            throw ex;
        }
    }

    public void assignNhanSuToHangMuc(int maSK, int maHM, int maNS, String nhiemVu) {
        AuthorizationService.requireManagerOrAdmin();

        String normalizedTask = nhiemVu == null ? "" : nhiemVu.trim();
        if (maSK <= 0 || maHM <= 0 || maNS <= 0) {
            throw new IllegalArgumentException("Sự kiện, hạng mục và nhân sự phải hợp lệ.");
        }

        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();

            NhanSu nhanSu = session.get(NhanSu.class, maNS);
            if (nhanSu == null) {
                throw new IllegalArgumentException("Không tìm thấy nhân sự.");
            }

            HangMucKichBan hangMuc = session.get(HangMucKichBan.class, maHM);
            if (hangMuc == null || hangMuc.getSuKienTiec() == null || hangMuc.getSuKienTiec().getMaSK() != maSK) {
                throw new IllegalArgumentException("Hạng mục không thuộc sự kiện đã chọn.");
            }

            // Mỗi hạng mục chỉ cho một người phụ trách chính.
            Long assignedToCurrentHangMuc = session.createQuery(
                            "SELECT COUNT(pc) FROM PhanCongNhanSu pc " +
                                    "WHERE pc.hangMuc.maHM = :maHM AND pc.nhanSu.maNS <> :maNS",
                            Long.class)
                    .setParameter("maHM", maHM)
                    .setParameter("maNS", maNS)
                    .uniqueResult();
            if (assignedToCurrentHangMuc != null && assignedToCurrentHangMuc > 0) {
                throw new IllegalArgumentException("Hạng mục đã có người phụ trách, không thể phân công thêm.");
            }

            // Nhân sự đã có hạng mục khác thì không nhận thêm.
            List<Object[]> existingOtherAssignments = session.createQuery(
                            "SELECT pc.hangMuc.maHM, pc.hangMuc.tenHM " +
                                    "FROM PhanCongNhanSu pc " +
                                    "WHERE pc.nhanSu.maNS = :maNS AND pc.hangMuc.maHM <> :maHM",
                            Object[].class)
                    .setParameter("maNS", maNS)
                    .setParameter("maHM", maHM)
                    .setMaxResults(1)
                    .list();
            if (!existingOtherAssignments.isEmpty()) {
                Object[] row = existingOtherAssignments.get(0);
                throw new IllegalArgumentException(
                        "Nhân sự đã được phân công ở hạng mục khác (" + row[1] + " - Mã " + row[0] + ")."
                );
            }

            // Upsert phân công theo cặp hạng mục - nhân sự.
            PhanCongNhanSuId id = new PhanCongNhanSuId(maHM, maNS);
            PhanCongNhanSu existing = session.get(PhanCongNhanSu.class, id);
            if (existing == null) {
                PhanCongNhanSu created = new PhanCongNhanSu();
                created.setHangMuc(hangMuc);
                created.setNhanSu(nhanSu);
                created.setNhiemVu(normalizedTask);
                session.persist(created);
            } else {
                existing.setNhiemVu(normalizedTask);
            }

            transaction.commit();
        } catch (Exception ex) {
            if (transaction != null) {
                transaction.rollback();
            }
            throw ex;
        }
    }

    public void deleteByHangMucAndNhanSu(int maHM, int maNS) {
        AuthorizationService.requireManagerOrAdmin();
        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();
            PhanCongNhanSu item = session.get(PhanCongNhanSu.class, new PhanCongNhanSuId(maHM, maNS));
            if (item != null) {
                session.remove(item);
            }
            transaction.commit();
        } catch (Exception ex) {
            if (transaction != null) {
                transaction.rollback();
            }
            throw ex;
        }
    }
}

package scriptmanager.service;

import org.hibernate.Session;
import org.hibernate.Transaction;
import scriptmanager.config.HibernateUtil;
import scriptmanager.entity.assignment.PhanCongNhanSu;
import scriptmanager.entity.assignment.pk.PhanCongNhanSuId;
import scriptmanager.entity.core.HangMucKichBan;
import scriptmanager.entity.user.NhanSu;
import scriptmanager.exception.BusinessRuleException;
